import requests

url = "http://127.0.0.1:8000/api/batch-recommendations"
payload = {
    "skills": [
        {
            "skill": "python",
            "preferences": ["Backend Developer", "FastAPI"]
        }
    ],
    "max_results": 10,
    "language": "en"
}

response = requests.post(url, json=payload)
data = response.json()

for skill_result in data['results']:
    print(f"Skill: {skill_result['skill']}")
    print(f"Found {skill_result['total_results']} recommendations")
    for course in skill_result['recommendations']:
        print(f"  - {course['title']} ({course['provider']})")
        print(f"    Score: {course['relevance_score']:.2f}")

import requests

url = "http://127.0.0.1:8000/api/batch-recommendations"
payload = {
    "skills": [
        {
            "skill": "python",
            "preferences": ["Backend Developer", "FastAPI"]
        },
        {
            "skill": "docker",
            "preferences": ["Backend Developer", "microservices"]
        },
        {
            "skill": "postgresql",
            "preferences": ["database optimization"]
        }
    ],
    "max_results": 5,
    "language": "en"
}

response = requests.post(url, json=payload)
data = response.json()

print(f"Total skills processed: {data['metadata']['total_skills']}")
print(f"Language: {data['metadata'].get('language', 'all')}\n")

for skill_result in data['results']:
    print(f"\n{'='*60}")
    print(f"Skill: {skill_result['skill']}")
    print(f"Total Results: {skill_result['total_results']}")
    print('='*60)

    for idx, course in enumerate(skill_result['recommendations'], 1):
        print(f"\n{idx}. {course['title']}")
        print(f"   Provider: {course['provider']}")
        print(f"   URL: {course['url']}")
        print(f"   Score: {course['relevance_score']:.2f}")
        print(f"   Tags: {', '.join(course['tags'][:5])}")

