const url = 'http://127.0.0.1:8000/api/batch-recommendations';
const payload = {
  skills: [
    {
      skill: 'python',
      preferences: ['Backend Developer', 'FastAPI']
    }
  ],
  max_results: 10,
  language: 'en'
};

fetch(url, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload)
})
  .then(response => response.json())
  .then(data => {
    data.results.forEach(skillResult => {
      console.log(`Skill: ${skillResult.skill}`);
      console.log(`Found ${skillResult.total_results} recommendations`);
      skillResult.recommendations.forEach(course => {
        console.log(`  - ${course.title} (${course.provider})`);
        console.log(`    Score: ${course.relevance_score.toFixed(2)}`);
      });
    });
  })
  .catch(error => console.error('Error:', error));

const url = 'http://127.0.0.1:8000/api/batch-recommendations';
const payload = {
  skills: [
    {
      skill: 'python',
      preferences: ['Backend Developer', 'FastAPI']
    },
    {
      skill: 'docker',
      preferences: ['Backend Developer', 'microservices']
    },
    {
      skill: 'postgresql',
      preferences: ['database optimization']
    }
  ],
  max_results: 5,
  language: 'en'
};

fetch(url, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload)
})
  .then(response => response.json())
  .then(data => {
    console.log(`Total skills: ${data.metadata.total_skills}`);
    console.log(`Language: ${data.metadata.language || 'all'}\n`);

    data.results.forEach(skillResult => {
      console.log(`\n${'='.repeat(60)}`);
      console.log(`Skill: ${skillResult.skill}`);
      console.log(`Total Results: ${skillResult.total_results}`);
      console.log('='.repeat(60));

      skillResult.recommendations.forEach((course, idx) => {
        console.log(`\n${idx + 1}. ${course.title}`);
        console.log(`   Provider: ${course.provider}`);
        console.log(`   Score: ${course.relevance_score.toFixed(2)}`);
        console.log(`   Tags: ${course.tags.slice(0, 5).join(', ')}`);
      });
    });
  })
  .catch(error => console.error('Error:', error));
